1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	}
13	
14	const PROCESSING_FEE = 5;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const BLOCK_SIZE = 3;
26	const BLOCK_PREMIUM = 60;
27	
28	const CURSE_SURCHARGE_RATE = 0.5;
29	
30	const HIGH_ENCHANTMENT_THRESHOLD = 5;
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
32	
33	function countByType(items: QuoteItem[]): Map<string, number> {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	}
40	
41	function priceGroup(type: string, count: number): number {
42	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
43	}
44	
45	function surchargeFor(
46	  items: QuoteItem[],
47	  applies: (item: QuoteItem) => boolean,
48	  rate: number,
49	): number {
50	  let surcharge = 0;
51	  for (const item of items) {
52	    if (applies(item)) {
53	      surcharge += BASE_PREMIUMS[item.type] * rate;
54	    }
55	  }
56	  return surcharge;
57	}
58	
59	function curseSurchargeFor(items: QuoteItem[]): number {
60	  return surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
61	}
62	
63	function highEnchantmentSurchargeFor(items: QuoteItem[]): number {
64	  return surchargeFor(
65	    items,
66	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
67	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
68	  );
69	}
70	
71	function basePremiumFor(items: QuoteItem[]): number {
72	  const countsByType = countByType(items);
73	
74	  let basePremium = 0;
75	  for (const [type, count] of countsByType) {
76	    basePremium += priceGroup(type, count);
77	  }
78	  return basePremium + curseSurchargeFor(items) + highEnchantmentSurchargeFor(items);
79	}
80	
81	export function quote(input: QuoteInput): number {
82	  return basePremiumFor(input.items) + PROCESSING_FEE;
83	}
84	
85	export function claim(input: unknown): number {
86	  return undefined as unknown as number;
87	}
